export function getGame(slug: string): Game | undefined {
  return games.find((g) => g.slug === slug);
}

export function getLatestGames(count = 10): Game[] {
  return [...games]
    .sort(
      (a, b) =>
        new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
    )
    .slice(0, count);
}
